import React from 'react';

interface FiltersProps {
  onSearchChange: (val: string) => void;
  onSourceChange: (val: string) => void;
  onSubCategoryChange: (val: string) => void;
  sources: string[];
  subCategories: string[];
}

const Filters: React.FC<FiltersProps> = ({ 
  onSearchChange, 
  onSourceChange, 
  onSubCategoryChange, 
  sources, 
  subCategories 
}) => {
  return (
    <div className="bg-white p-4 rounded-xl border border-slate-200 shadow-sm flex flex-col md:flex-row gap-4 items-center">
      <div className="relative flex-grow w-full">
        <input
          type="text"
          placeholder="Rechercher un outil, SaaS..."
          className="w-full pl-10 pr-4 py-2 border border-slate-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500/20 focus:border-blue-500 text-sm transition-all"
          onChange={(e) => onSearchChange(e.target.value)}
        />
        <svg className="absolute left-3 top-2.5 h-4 w-4 text-slate-400" fill="none" viewBox="0 0 24 24" stroke="currentColor">
          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" />
        </svg>
      </div>

      <div className="flex gap-2 w-full md:w-auto">
        <select 
          onChange={(e) => onSourceChange(e.target.value)}
          className="bg-white border border-slate-200 text-slate-600 text-sm rounded-lg focus:ring-blue-500 focus:border-blue-500 block w-full p-2.5 outline-none cursor-pointer"
        >
          <option value="">Toutes les sources</option>
          {sources.map(s => <option key={s} value={s}>{s}</option>)}
        </select>

        {subCategories.length > 0 && (
          <select 
            onChange={(e) => onSubCategoryChange(e.target.value)}
            className="bg-white border border-slate-200 text-slate-600 text-sm rounded-lg focus:ring-blue-500 focus:border-blue-500 block w-full p-2.5 outline-none cursor-pointer"
          >
            <option value="">Type d'outil</option>
            {subCategories.map(sc => <option key={sc} value={sc}>{sc}</option>)}
          </select>
        )}
      </div>
    </div>
  );
};

export default Filters;

import React, { useState, useMemo, useEffect } from 'react';
import { useParams } from 'react-router-dom';
import { CATEGORIES, MOCK_DATA } from '../constants';
import { CategoryType } from '../types';
import ToolCard from '../components/ToolCard';
import Filters from '../components/Filters';

const Category: React.FC = () => {
  const { id } = useParams<{ id: string }>();
  const [search, setSearch] = useState('');
  const [source, setSource] = useState('');
  const [subCategory, setSubCategory] = useState('');

  const category = useMemo(() => 
    CATEGORIES.find(c => c.id === id) || CATEGORIES[0], 
  [id]);

  useEffect(() => {
    // Reset filters when category changes
    setSearch('');
    setSource('');
    setSubCategory('');
    window.scrollTo(0, 0);

    // Update SEO title
    document.title = `${category.label} | SaaS Hub Aggregator`;
  }, [id, category.label]);

  const filteredData = useMemo(() => {
    return MOCK_DATA.filter(item => {
      const matchCategory = item.category === id;
      const matchSearch = item.name.toLowerCase().includes(search.toLowerCase()) || 
                          item.description.toLowerCase().includes(search.toLowerCase());
      const matchSource = source === '' || item.source === source;
      const matchSub = subCategory === '' || item.subCategory === subCategory;
      return matchCategory && matchSearch && matchSource && matchSub;
    });
  }, [id, search, source, subCategory]);

  const sources = useMemo(() => {
    const s = new Set(MOCK_DATA.filter(i => i.category === id).map(i => i.source));
    return Array.from(s);
  }, [id]);

  const subCategories = useMemo(() => {
    const sc = new Set(MOCK_DATA.filter(i => i.category === id && i.subCategory).map(i => i.subCategory as string));
    return Array.from(sc);
  }, [id]);

  return (
    <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-12 min-h-screen">
      <header className="mb-12">
        <div className="flex items-center gap-3 mb-4">
          <span className="text-4xl">{category.icon}</span>
          <h1 className="text-3xl font-extrabold text-slate-900">{category.label}</h1>
        </div>
        <p className="text-lg text-slate-600 max-w-2xl">{category.description}</p>
      </header>

      <section className="mb-10">
        <Filters 
          onSearchChange={setSearch}
          onSourceChange={setSource}
          onSubCategoryChange={setSubCategory}
          sources={sources}
          subCategories={subCategories}
        />
      </section>

      {filteredData.length > 0 ? (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
          {filteredData.map(tool => (
            <ToolCard key={tool.id} tool={tool} />
          ))}
        </div>
      ) : (
        <div className="text-center py-24 bg-white rounded-3xl border border-dashed border-slate-300">
          <svg className="mx-auto h-12 w-12 text-slate-400 mb-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" />
          </svg>
          <h3 className="text-lg font-medium text-slate-900">Aucun outil trouvé</h3>
          <p className="mt-1 text-slate-500 text-sm">Essayez de modifier vos filtres ou de faire une recherche plus large.</p>
        </div>
      )}
    </div>
  );
};

export default Category;

