import React, { useState, useEffect } from 'react';
import { CATEGORIES } from '../constants';
import { CategoryType, ToolItem } from '../types';

const Dashboard: React.FC = () => {
  const [submissions, setSubmissions] = useState<ToolItem[]>([]);
  const [formData, setFormData] = useState({
    name: '',
    description: '',
    category: CategoryType.AI_TOOLS,
    price: '',
    logo: '',
    link: '',
    source: 'Direct',
    tags: ''
  });
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [showSuccess, setShowSuccess] = useState(false);

  useEffect(() => {
    const saved = localStorage.getItem('saas_hub_submissions');
    if (saved) {
      setSubmissions(JSON.parse(saved));
    }
  }, []);

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement | HTMLSelectElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setIsSubmitting(true);

    // Simulate API call
    setTimeout(() => {
      const newTool: ToolItem = {
        id: `sub-${Date.now()}`,
        name: formData.name,
        description: formData.description,
        category: formData.category,
        price: formData.price,
        logo: formData.logo || `https://picsum.photos/seed/${formData.name}/200/200`,
        link: formData.link,
        source: formData.source,
        tags: formData.tags.split(',').map(t => t.trim()),
        isNew: true
      };

      const updatedSubmissions = [newTool, ...submissions];
      setSubmissions(updatedSubmissions);
      localStorage.setItem('saas_hub_submissions', JSON.stringify(updatedSubmissions));

      setIsSubmitting(false);
      setShowSuccess(true);
      setFormData({
        name: '',
        description: '',
        category: CategoryType.AI_TOOLS,
        price: '',
        logo: '',
        link: '',
        source: 'Direct',
        tags: ''
      });

      setTimeout(() => setShowSuccess(false), 5000);
    }, 1000);
  };

  return (
    <div className="max-w-full mx-auto px-6 md:px-12 py-12 bg-slate-50 min-h-screen">
      <div className="flex flex-col lg:flex-row gap-12">

        {/* Left Column: Form and Stats */}
        <div className="lg:w-2/5 space-y-8">
          <div>
            <h1 className="text-4xl font-extrabold text-slate-900 mb-2 tracking-tight">Tableau de bord</h1>
            <p className="text-slate-500 text-lg">Soumettez vos outils et suivez vos publications en temps réel.</p>
          </div>

          {/* Stats Grid */}
          <div className="grid grid-cols-3 gap-4">
            <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm">
              <span className="block text-slate-400 text-xs font-bold uppercase mb-1">Total</span>
              <span className="text-2xl font-bold text-slate-900">{submissions.length}</span>
            </div>
            <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm">
              <span className="block text-amber-400 text-xs font-bold uppercase mb-1">En attente</span>
              <span className="text-2xl font-bold text-amber-600">{submissions.filter(s => s.isNew).length}</span>
            </div>
            <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm">
              <span className="block text-green-400 text-xs font-bold uppercase mb-1">Actifs</span>
              <span className="text-2xl font-bold text-green-600">0</span>
            </div>
          </div>

          {/* Form Card */}
          <div className="bg-white rounded-[2rem] border border-slate-200 shadow-xl p-8 overflow-hidden relative">
            <h2 className="text-2xl font-bold text-slate-900 mb-6 flex items-center gap-2">
              <span className="bg-blue-100 text-blue-600 p-2 rounded-lg">🚀</span>
              Nouvelle Soumission
            </h2>

            {showSuccess && (
              <div className="mb-6 p-4 bg-green-50 border border-green-200 text-green-700 rounded-xl animate-bounce">
                ✅ Votre outil a été soumis avec succès et est en attente de modération !
              </div>
            )}

            <form onSubmit={handleSubmit} className="space-y-4">
              <div>
                <label className="block text-sm font-bold text-slate-700 mb-1">Nom du produit *</label>
                <input
                  required
                  type="text"
                  name="name"
                  value={formData.name}
                  onChange={handleInputChange}
                  placeholder="Ex: Jasper AI, Canva..."
                  className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-blue-500 outline-none transition-all"
                />
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-sm font-bold text-slate-700 mb-1">Catégorie *</label>
                  <select
                    name="category"
                    value={formData.category}
                    onChange={handleInputChange}
                    className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-blue-500 outline-none transition-all"
                  >
                    {CATEGORIES.map(cat => (
                      <option key={cat.id} value={cat.id}>{cat.label}</option>
                    ))}
                  </select>
                </div>
                <div>
                  <label className="block text-sm font-bold text-slate-700 mb-1">Prix indicatif *</label>
                  <input
                    required
                    type="text"
                    name="price"
                    value={formData.price}
                    onChange={handleInputChange}
                    placeholder="Ex: 29$/mois, Gratuit..."
                    className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-blue-500 outline-none transition-all"
                  />
                </div>
              </div>

              <div>
                <label className="block text-sm font-bold text-slate-700 mb-1">Lien du site / Affiliation *</label>
                <input
                  required
                  type="url"
                  name="link"
                  value={formData.link}
                  onChange={handleInputChange}
                  placeholder="https://..."
                  className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-blue-500 outline-none transition-all"
                />
              </div>

              <div>
                <label className="block text-sm font-bold text-slate-700 mb-1">Description courte *</label>
                <textarea
                  required
                  name="description"
                  value={formData.description}
                  onChange={handleInputChange}
                  rows={3}
                  placeholder="Décrivez votre outil en quelques phrases..."
                  className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-blue-500 outline-none transition-all resize-none"
                ></textarea>
              </div>

              <div>
                <label className="block text-sm font-bold text-slate-700 mb-1">Tags (séparés par des virgules)</label>
                <input
                  type="text"
                  name="tags"
                  value={formData.tags}
                  onChange={handleInputChange}
                  placeholder="IA, Design, Productivity..."
                  className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-blue-500 outline-none transition-all"
                />
              </div>

              <button
                type="submit"
                disabled={isSubmitting}
                className={`w-full py-4 rounded-xl font-bold text-white transition-all shadow-lg ${
                  isSubmitting ? 'bg-slate-400' : 'bg-slate-900 hover:bg-blue-600 shadow-blue-500/10'
                }`}
              >
                {isSubmitting ? 'Envoi en cours...' : 'Soumettre le produit'}
              </button>
            </form>
          </div>
        </div>

        {/* Right Column: History List */}
        <div className="lg:w-3/5">
          <div className="bg-white rounded-[2.5rem] border border-slate-200 shadow-sm p-8 min-h-[600px]">
            <div className="flex items-center justify-between mb-8">
              <h2 className="text-2xl font-bold text-slate-900 tracking-tight">Historique des soumissions</h2>
              <span className="text-sm text-slate-500">{submissions.length} outils au total</span>
            </div>

            {submissions.length === 0 ? (
              <div className="flex flex-col items-center justify-center h-96 text-center border-2 border-dashed border-slate-100 rounded-[2rem]">
                <div className="bg-slate-50 p-6 rounded-full mb-4">
                  <svg className="w-12 h-12 text-slate-300" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1} d="M12 9v3m0 0v3m0-3h3m-3 0H9m12 0a9 9 0 11-18 0 9 9 0 0118 0z" />
                  </svg>
                </div>
                <h3 className="text-xl font-bold text-slate-900">Aucune soumission</h3>
                <p className="text-slate-500 max-w-xs mt-2">Utilisez le formulaire à gauche pour soumettre votre premier outil digital.</p>
              </div>
            ) : (
              <div className="overflow-x-auto">
                <table className="w-full">
                  <thead>
                    <tr className="text-left border-b border-slate-100">
                      <th className="pb-4 font-bold text-slate-400 uppercase text-xs tracking-wider">Outil</th>
                      <th className="pb-4 font-bold text-slate-400 uppercase text-xs tracking-wider">Catégorie</th>
                      <th className="pb-4 font-bold text-slate-400 uppercase text-xs tracking-wider">Statut</th>
                      <th className="pb-4 font-bold text-slate-400 uppercase text-xs tracking-wider text-right">Date</th>
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-slate-50">
                    {submissions.map((item) => (
                      <tr key={item.id} className="group hover:bg-slate-50 transition-colors">
                        <td className="py-4">
                          <div className="flex items-center gap-3">
                            <img src={item.logo} className="w-10 h-10 rounded-lg object-cover" alt={item.name} />
