        name: '', 
        description: '', 
        category: categories[0]?.id || '', 
        subCategory: '',
        price: '', 
        logo: '', 
        link: '', 
        source: 'Direct', 
        tags: '' 
      });
      setTimeout(() => setShowSuccess(false), 5000);
    }, 800);
  };

